SELECT DISTINCT maintainer_id
FROM packages
WHERE license = 'GPL-3.0';

SELECT DISTINCT developers.developer_name
FROM developers
JOIN conflicts ON conflicts.resolved_by = developers.developer_id;

SELECT package_name 
FROM packages 
WHERE package_id IN (SELECT package_id FROM conflicts);

SELECT packages.package_name, versions.version_number
FROM packages
INNER JOIN versions ON packages.package_id = versions.package_id;

SELECT p.package_name, d.developer_name
FROM packages p
INNER JOIN developers d ON p.maintainer_id = d.developer_id;

SELECT package_id, version_id, description, resolution, created_at, updated_at, resolved_by, resolved_date
FROM conflicts
WHERE conflict_id = 1;

SELECT packages.package_name, developers.developer_name
FROM packages
LEFT JOIN developers ON packages.maintainer_id = developers.developer_id;

SELECT p.package_name, p.description
FROM packages p
JOIN conflicts c ON p.package_id = c.package_id;
